<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;">King Khalid International Airport (RUH)</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;text-align:center;">~25 min</td></tr>
<tr><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Kingdom Centre Tower</td><td style="padding:10px;border-bottom:1px solid #e2e8f0;text-align:center;">~10 min</td></tr>
<tr style="background:#f8fafc;"><td style="padding:10px;">King Abdullah Financial District</td><td style="padding:10px;text-align:center;">~10 min</td></tr>
</tbody></table>
<h2>What''s Inside</h2>
<table style="width:100%;border-collapse:collapse;margin:16px 0;font-size:14px;"><thead><tr style="background:#1e3a5f;color:#fff;"><th style="padding:10px;text-align:left;">Feature</th><th style="padding:10px;">Highlight</th></tr></thead><tbody>
<tr style="background:#f8fafc;"><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>Reading Halls</strong></td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Quiet study spaces beneath the glass facade</td></tr>
<tr><td style="padding:10px;border-bottom:1px solid #e2e8f0;"><strong>Manuscripts &amp; Archives</strong></td><td style="padding:10px;border-bottom:1px solid #e2e8f0;">Historic Arabic manuscripts and periodicals</td></tr>
<tr style="background:#f8fafc;"><td style="padding:10px;"><strong>Exhibition Spaces</strong></td><td style="padding:10px;">Rotating cultural and literary exhibitions</td></tr>
</tbody></table>
