<div style="background:#f8fafc;border-radius:12px;padding:20px;margin:16px 0;">
<div style="margin-bottom:8px;"><span style="display:inline-block;width:140px;font-size:13px;">Daytime</span><div style="display:inline-block;background:#eab308;height:14px;border-radius:4px;width:40%;vertical-align:middle;"></div><span style="margin-left:8px;font-size:12px;color:#ca8a04;">Hazy Views</span></div>
